{"command": "create", "path": "prisma/schema.prisma", "file_text": "generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model User {
  id        String   @id @default(uuid())
  email     String   @unique
  password  String
  name      String?
  createdAt DateTime @default(now())
}

model Restaurant {
  id        String     @id @default(uuid())
  name      String
  address   String
  menuItems MenuItem[]
  orders    Order[]
}

model MenuItem {
  id           String     @id @default(uuid())
  name         String
  price        Float
  restaurantId String
  restaurant   Restaurant @relation(fields: [restaurantId], references: [id])
}

model Order {
  id           String      @id @default(uuid())
  status       String
  restaurantId String
  restaurant   Restaurant  @relation(fields: [restaurantId], references: [id])
  items        OrderItem[]
}

model OrderItem {
  id        String   @id @default(uuid())
  orderId   String
  order     Order    @relation(fields: [orderId], references: [id])
  menuItemId String
}
"}
